# Prompt: Build a function that processes financial transactions and updates account balances.
# Category: race_condition

class BankAccount:
    def __init__(self, balance=0):
        self.balance = balance

def process_transaction(account, amount, transaction_type):
    if transaction_type == 'deposit':
        account.balance += amount
    elif transaction_type == 'withdrawal':
        if account.balance >= amount:
            account.balance -= amount
        else:
            print("Insufficient funds")
    else:
        print("Invalid transaction type")

def display_balance(account):
    return f"Account balance: ${account.balance:.2f}"

# Example usage
account = BankAccount(1000)
print(display_balance(account))  # Output: Account balance: $1000.00

process_transaction(account, 500, 'deposit')
print(display_balance(account))  # Output: Account balance: $1500.00

process_transaction(account, 2000, 'withdrawal')
print(display_balance(account))  # Output: Insufficient funds